Page._content:
@import url("https://cdn.jsdelivr.net/npm/lxgw-wenkai-screen-webfont@1.7.0/style.css");

:root {
  --hane-ink: #2f4358;
  --hane-muted: #708596;
  --hane-soft: #edf7f9;
  --hane-glass: rgba(255, 255, 255, 0.6);
  --hane-glass-strong: rgba(255, 255, 255, 0.76);
  --hane-glass-border: rgba(255, 255, 255, 0.5);
  --hane-water: #9fd8ee;
  --hane-blush: #f2c8d6;
  --hane-mint: #c9eadf;
  --hane-iris: #aeb8dd;
  --hane-shadow: 0 16px 48px rgba(80, 118, 145, 0.16);
  --hane-blur: blur(18px) saturate(150%);
}

[data-theme='dark'] {
  --hane-ink: #dceaf3;
  --hane-muted: #a9bdcb;
  --hane-soft: #1b2d3a;
  --hane-glass: rgba(20, 31, 42, 0.58);
  --hane-glass-strong: rgba(28, 41, 55, 0.74);
  --hane-glass-border: rgba(185, 221, 238, 0.18);
  --hane-water: #7fc4e6;
  --hane-blush: #c99bb5;
  --hane-mint: #94d4c6;
  --hane-shadow: 0 18px 55px rgba(0, 0, 0, 0.34);
}

html {
  scroll-behavior: smooth;
}

html,
body,
button,
input,
textarea,
select {
  font-family: "LXGW WenKai Screen", "Noto Serif SC", "Songti SC", "Microsoft YaHei", sans-serif;
}

body {
  color: var(--hane-ink);
  background:
    linear-gradient(110deg, rgba(255, 255, 255, 0.72) 0 1px, transparent 1px 18px),
    radial-gradient(circle at 18% 12%, rgba(255, 255, 255, 0.86), transparent 28rem),
    radial-gradient(circle at 82% 18%, rgba(200, 234, 241, 0.58), transparent 30rem),
    radial-gradient(circle at 28% 82%, rgba(243, 203, 218, 0.4), transparent 32rem),
    linear-gradient(135deg, #f8fcfd 0%, #edf8fb 46%, #fbf3f7 100%) !important;
  background-size: 180px 180px, auto, auto, auto, auto !important;
  background-attachment: fixed !important;
}

[data-theme='dark'] body {
  background:
    radial-gradient(circle at 16% 10%, rgba(91, 140, 166, 0.32), transparent 28rem),
    radial-gradient(circle at 86% 18%, rgba(115, 92, 134, 0.28), transparent 30rem),
    radial-gradient(circle at 50% 88%, rgba(65, 107, 103, 0.22), transparent 34rem),
    linear-gradient(135deg, #101923 0%, #162433 52%, #211b2a 100%) !important;
}

body::before,
body::after {
  position: fixed;
  inset: 0;
  z-index: -3;
  pointer-events: none;
  content: "";
}

body::before {
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.18) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.14) 1px, transparent 1px);
  background-size: 84px 84px;
  mask-image: linear-gradient(to bottom, transparent, #000 16%, #000 72%, transparent);
}

body::after {
  background:
    linear-gradient(105deg, transparent 0 46%, rgba(255, 255, 255, 0.1) 46.2%, transparent 47% 100%),
    linear-gradient(105deg, transparent 0 62%, rgba(159, 216, 238, 0.08) 62.2%, transparent 63% 100%);
  background-size: 620px 620px, 920px 920px;
  opacity: 0.28;
}

#web_bg,
#web_bg::before,
#footer::before,
#page-header::before {
  background: transparent !important;
}

#rain-canvas {
  position: fixed;
  inset: 0;
  z-index: 3;
  width: 100%;
  height: 100%;
  pointer-events: none;
  mix-blend-mode: screen;
}

#body-wrap,
#page-header,
#content-inner,
#footer,
#nav {
  position: relative;
}

#body-wrap,
#page-header,
#content-inner,
#footer {
  z-index: 2;
}

#page-header {
  overflow: hidden;
}

#page-header::after {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  content: "";
  background:
    linear-gradient(to bottom, rgba(27, 51, 72, 0.12), rgba(238, 248, 251, 0.12) 52%, rgba(248, 252, 253, 0.34)),
    linear-gradient(115deg, transparent 0 53%, rgba(255, 255, 255, 0.08) 53.18%, transparent 54% 100%);
  background-size: auto, 780px 780px;
}

#page-header > * {
  position: relative;
  z-index: 1;
}

#page-header.full_page {
  min-height: 78vh;
}

#page-header.not-home-page {
  height: 22rem;
}

#page-header #site-info {
  box-sizing: border-box;
  width: 100%;
  max-width: none;
  padding: 0 1.25rem;
  margin: 0 auto;
  text-align: center;
  text-shadow: 0 10px 30px rgba(38, 65, 90, 0.42);
}

#site-title {
  letter-spacing: 0;
  color: rgba(255, 255, 255, 0.96);
  font-size: 2.55rem;
  font-weight: 700;
  line-height: 1.18;
}

#site-subtitle {
  display: block;
  max-width: 46rem;
  margin: 0.55rem auto 0;
  color: rgba(255, 255, 255, 0.9);
  line-height: 1.65;
  text-shadow: 0 8px 24px rgba(38, 65, 90, 0.34);
}

#subtitle {
  white-space: normal;
  overflow-wrap: anywhere;
}

#nav {
  background: rgba(255, 255, 255, 0.24);
  border-bottom: 1px solid rgba(255, 255, 255, 0.28);
  box-shadow: none;
  font-size: 1.08rem;
  font-weight: 600;
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

#nav.show {
  background: rgba(255, 255, 255, 0.66);
  box-shadow: 0 12px 32px rgba(91, 121, 150, 0.12);
}

[data-theme='dark'] #nav,
[data-theme='dark'] #nav.show {
  background: rgba(18, 29, 40, 0.58);
  border-bottom-color: rgba(185, 221, 238, 0.14);
}

#nav a,
#nav #site-name,
#nav .menus_item_child li a {
  color: var(--hane-ink);
}

#nav .menus_items .menus_item > a {
  display: inline-flex;
  gap: 0.22rem;
  align-items: center;
  height: 2.25rem;
  padding: 0 0.45rem;
  border-radius: 8px;
  transition: background 0.22s ease, color 0.22s ease, transform 0.22s ease;
}

#nav .menus_items .menus_item > a:hover {
  color: #3e7fa3;
  background: rgba(255, 255, 255, 0.36);
  transform: translateY(-1px);
}

#nav .site-page i,
#nav #toggle-menu i {
  margin-right: 0;
  font-size: 1.12rem;
  color: #6a9fbb;
}

#nav .site-name {
  font-size: 1.18rem;
}

#nav .menus_item_child,
#nav .menus_items .menus_item .menus_item_child {
  background: var(--hane-glass-strong);
  border: 1px solid var(--hane-glass-border);
  box-shadow: var(--hane-shadow);
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

#recent-posts > .recent-post-item,
.layout > div:first-child:not(.recent-posts),
.layout > .aside-content .card-widget,
#archive,
#page,
#post,
#tag,
#category,
#category-bar,
#pagination .page-number,
#pagination .extend,
#pagination .space {
  background:
    linear-gradient(145deg, rgba(255, 255, 255, 0.32), rgba(255, 255, 255, 0.08)),
    var(--hane-glass);
  border: 1px solid var(--hane-glass-border);
  box-shadow: var(--hane-shadow);
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

#recent-posts > .recent-post-item,
.layout > div:first-child:not(.recent-posts),
.layout > .aside-content .card-widget,
#archive,
#page,
#post,
#tag,
#category {
  border-radius: 8px;
}

#recent-posts > .recent-post-item {
  position: relative;
  overflow: hidden;
  transition: transform 0.25s ease, box-shadow 0.25s ease, border-color 0.25s ease;
}

#recent-posts > .recent-post-item::before {
  position: absolute;
  inset: 0 auto 0 0;
  width: 3px;
  content: "";
  background: linear-gradient(to bottom, var(--hane-water), var(--hane-blush), var(--hane-mint));
  opacity: 0.65;
}

#recent-posts > .recent-post-item:hover {
  border-color: rgba(159, 216, 238, 0.7);
  box-shadow: 0 22px 70px rgba(83, 127, 158, 0.22);
  transform: translateY(-4px);
}

#recent-posts > .recent-post-item .post_cover img.post_bg {
  filter: saturate(108%) contrast(96%) brightness(1.04);
  transition: transform 0.5s ease, filter 0.5s ease;
}

#recent-posts > .recent-post-item:hover .post_cover img.post_bg {
  filter: saturate(116%) contrast(98%) brightness(1.08);
  transform: scale(1.04);
}

.post-meta,
.post-meta a,
.article-meta-wrap,
.article-meta-wrap a,
.card-info-data,
.card-info-data a,
.aside-list .content time,
.aside-list .content .name {
  color: var(--hane-muted) !important;
}

#post-info .post-title,
.recent-post-info .article-title,
.card-widget .item-headline,
#page h1,
#post h1,
#archive h1,
#tag h1,
#category h1 {
  color: var(--hane-ink);
}

.recent-post-info .article-title {
  line-height: 1.45;
}

.recent-post-info .content,
#article-container {
  color: #40576a;
  line-height: 1.95;
}

[data-theme='dark'] .recent-post-info .content,
[data-theme='dark'] #article-container {
  color: #c8d8e2;
}

#article-container h1,
#article-container h2,
#article-container h3,
#article-container h4 {
  letter-spacing: 0;
}

a {
  color: #4a92b8;
}

a:hover {
  color: #d57d9f;
}

#aside-content .card-info .author-info-name {
  color: var(--hane-ink);
  font-size: 1.18rem;
}

#aside-content .card-info .author-info-description,
#aside-content .card-announcement .announcement_content {
  color: var(--hane-muted);
}

#aside-content .card-info #card-info-btn,
.button--animated,
#pagination .page-number.current {
  background: linear-gradient(135deg, #8fcde8, #d9bfdc);
  border: 0;
  box-shadow: 0 10px 24px rgba(104, 162, 188, 0.22);
  color: #fff !important;
}

#aside-content .card-info #card-info-btn:hover,
.button--animated:hover {
  box-shadow: 0 14px 32px rgba(132, 144, 189, 0.28);
  filter: brightness(1.03);
}

blockquote,
.note {
  background: rgba(255, 255, 255, 0.42) !important;
  border-color: rgba(159, 216, 238, 0.72) !important;
  border-radius: 8px;
}

[data-theme='dark'] blockquote,
[data-theme='dark'] .note {
  background: rgba(25, 38, 51, 0.58) !important;
}

hr {
  border-color: rgba(159, 216, 238, 0.42);
}

#footer {
  background: transparent;
  color: var(--hane-muted);
}

#footer a {
  color: var(--hane-ink);
}

#rightside > div > button,
#rightside > div > a {
  background: var(--hane-glass-strong);
  border: 1px solid var(--hane-glass-border);
  box-shadow: 0 10px 28px rgba(79, 119, 148, 0.18);
  color: var(--hane-ink);
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

.guestbook-board {
  display: grid;
  gap: 1.2rem;
}

.guestbook-form {
  display: grid;
  gap: 0.85rem;
  padding: 1.1rem;
  background: rgba(255, 255, 255, 0.42);
  border: 1px solid var(--hane-glass-border);
  border-radius: 8px;
}

[data-theme='dark'] .guestbook-form {
  background: rgba(24, 38, 51, 0.46);
}

.guestbook-fields {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(13rem, 1fr));
  gap: 0.85rem;
}

.guestbook-form input,
.guestbook-form textarea {
  width: 100%;
  padding: 0.8rem 0.9rem;
  color: var(--hane-ink);
  background: rgba(255, 255, 255, 0.62);
  border: 1px solid rgba(159, 216, 238, 0.44);
  border-radius: 8px;
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease, background 0.2s ease;
}

[data-theme='dark'] .guestbook-form input,
[data-theme='dark'] .guestbook-form textarea {
  background: rgba(13, 24, 35, 0.5);
}

.guestbook-form textarea {
  min-height: 8.5rem;
  resize: vertical;
}

.guestbook-form input:focus,
.guestbook-form textarea:focus {
  background: rgba(255, 255, 255, 0.78);
  border-color: rgba(213, 125, 159, 0.7);
  box-shadow: 0 0 0 4px rgba(159, 216, 238, 0.18);
}

.guestbook-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  align-items: center;
  justify-content: space-between;
}

.guestbook-actions button {
  display: inline-flex;
  gap: 0.4rem;
  align-items: center;
  justify-content: center;
  min-height: 2.6rem;
  padding: 0 1.1rem;
  color: #fff;
  cursor: pointer;
  background: linear-gradient(135deg, var(--hane-water), var(--hane-blush));
  border: 0;
  border-radius: 8px;
  box-shadow: 0 10px 24px rgba(104, 162, 188, 0.22);
}

.guestbook-actions button[type='button'] {
  color: var(--hane-ink);
  background: rgba(255, 255, 255, 0.56);
  border: 1px solid var(--hane-glass-border);
}

.guestbook-hint {
  color: var(--hane-muted);
  font-size: 0.92rem;
}

.guestbook-list {
  display: grid;
  gap: 0.9rem;
}

.guestbook-empty,
.guestbook-message {
  padding: 1rem 1.05rem;
  background: rgba(255, 255, 255, 0.42);
  border: 1px solid var(--hane-glass-border);
  border-radius: 8px;
}

[data-theme='dark'] .guestbook-empty,
[data-theme='dark'] .guestbook-message {
  background: rgba(24, 38, 51, 0.46);
}

.guestbook-message-head {
  display: flex;
  gap: 0.7rem;
  align-items: baseline;
  justify-content: space-between;
  margin-bottom: 0.55rem;
}

.guestbook-message-name {
  color: var(--hane-ink);
  font-weight: 700;
}

.guestbook-message-date {
  color: var(--hane-muted);
  font-size: 0.86rem;
  white-space: nowrap;
}

.guestbook-message-body {
  margin: 0;
  color: var(--hane-ink);
  line-height: 1.9;
  white-space: pre-wrap;
}

.music-player-panel {
  display: grid;
  gap: 1rem;
}

.music-player-copy {
  padding: 1.1rem;
  background: rgba(255, 255, 255, 0.42);
  border: 1px solid var(--hane-glass-border);
  border-radius: 8px;
}

[data-theme='dark'] .music-player-copy {
  background: rgba(24, 38, 51, 0.46);
}

.music-player-copy h2 {
  margin: 0 0 0.35rem;
  color: var(--hane-ink);
}

.music-player-copy p {
  margin: 0;
  color: var(--hane-muted);
}

.music-page-aplayer.aplayer {
  margin: 0;
  overflow: hidden;
  color: var(--hane-ink);
  background: rgba(255, 255, 255, 0.54);
  border: 1px solid var(--hane-glass-border);
  border-radius: 8px;
  box-shadow: var(--hane-shadow);
}

[data-theme='dark'] .music-page-aplayer.aplayer {
  background: rgba(24, 38, 51, 0.6);
}

.music-page-aplayer.aplayer .aplayer-list,
.music-page-aplayer.aplayer .aplayer-info {
  border-color: rgba(159, 216, 238, 0.28);
}

.music-page-aplayer.aplayer .aplayer-list ol li {
  border-top-color: rgba(159, 216, 238, 0.2);
}

.music-page-aplayer.aplayer .aplayer-list ol li:hover,
.music-page-aplayer.aplayer .aplayer-list ol li.aplayer-list-light {
  background: rgba(159, 216, 238, 0.18);
}

#rain-control {
  position: fixed;
  bottom: 1.25rem;
  left: 1.25rem;
  z-index: 9;
  display: flex;
  gap: 0.65rem;
  align-items: end;
  pointer-events: none;
}

.rain-control-toggle,
.rain-control-panel {
  color: var(--hane-ink);
  pointer-events: auto;
  background:
    linear-gradient(145deg, rgba(255, 255, 255, 0.38), rgba(255, 255, 255, 0.12)),
    var(--hane-glass-strong);
  border: 1px solid var(--hane-glass-border);
  box-shadow: 0 14px 38px rgba(79, 119, 148, 0.18);
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

.rain-control-toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 2.75rem;
  height: 2.75rem;
  color: #5c99b9;
  cursor: pointer;
  border-radius: 8px;
  transition: transform 0.22s ease, color 0.22s ease, box-shadow 0.22s ease;
}

.rain-control-toggle:hover,
#rain-control.is-open .rain-control-toggle {
  color: #d18ca8;
  box-shadow: 0 16px 42px rgba(105, 151, 178, 0.24);
  transform: translateY(-2px);
}

.rain-control-toggle i {
  font-size: 1.08rem;
}

.rain-control-panel {
  width: 12.5rem;
  padding: 0.8rem 0.9rem;
  border-radius: 8px;
  opacity: 0;
  transform: translateY(0.45rem) scale(0.98);
  transform-origin: bottom left;
  transition: opacity 0.22s ease, transform 0.22s ease, visibility 0.22s ease;
  visibility: hidden;
}

#rain-control.is-open .rain-control-panel {
  opacity: 1;
  transform: translateY(0) scale(1);
  visibility: visible;
}

.rain-control-head,
.rain-control-scale {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.rain-control-head {
  margin-bottom: 0.55rem;
  font-size: 0.95rem;
  font-weight: 700;
}

.rain-control-value {
  min-width: 1.65rem;
  padding: 0.08rem 0.45rem;
  color: #fff;
  text-align: center;
  background: linear-gradient(135deg, #8fcde8, #d9bfdc);
  border-radius: 8px;
}

.rain-control-range {
  width: 100%;
  height: 1.25rem;
  margin: 0;
  appearance: none;
  cursor: pointer;
  background: transparent;
}

.rain-control-range::-webkit-slider-runnable-track {
  height: 0.42rem;
  background:
    linear-gradient(90deg, rgba(111, 180, 211, 0.72), rgba(222, 176, 207, 0.82)) 0 / var(--rain-progress, 50%) 100% no-repeat,
    linear-gradient(90deg, rgba(159, 216, 238, 0.3), rgba(217, 191, 220, 0.36));
  border: 1px solid rgba(255, 255, 255, 0.52);
  border-radius: 8px;
}

.rain-control-range::-webkit-slider-thumb {
  width: 1rem;
  height: 1rem;
  margin-top: -0.34rem;
  appearance: none;
  background: #fff;
  border: 2px solid #7bb9d5;
  border-radius: 50%;
  box-shadow: 0 6px 16px rgba(93, 139, 164, 0.28);
}

.rain-control-range::-moz-range-track {
  height: 0.42rem;
  background:
    linear-gradient(90deg, rgba(111, 180, 211, 0.72), rgba(222, 176, 207, 0.82)) 0 / var(--rain-progress, 50%) 100% no-repeat,
    linear-gradient(90deg, rgba(159, 216, 238, 0.3), rgba(217, 191, 220, 0.36));
  border: 1px solid rgba(255, 255, 255, 0.52);
  border-radius: 8px;
}

.rain-control-range::-moz-range-thumb {
  width: 1rem;
  height: 1rem;
  background: #fff;
  border: 2px solid #7bb9d5;
  border-radius: 50%;
  box-shadow: 0 6px 16px rgba(93, 139, 164, 0.28);
}

.rain-control-scale {
  margin-top: 0.35rem;
  color: var(--hane-muted);
  font-size: 0.78rem;
}

::selection {
  background: rgba(159, 216, 238, 0.48);
  color: #23435b;
}

@media (max-width: 768px) {
  #page-header.full_page {
    min-height: 68vh;
  }

  #page-header.not-home-page {
    height: 17rem;
  }

  #site-title {
    font-size: 1.9rem;
  }

  #site-subtitle {
    max-width: 21rem;
    font-size: 0.96rem;
  }

  #recent-posts > .recent-post-item,
  .layout > div:first-child:not(.recent-posts),
  .layout > .aside-content .card-widget,
  #archive,
  #page,
  #post,
  #tag,
  #category {
    border-radius: 8px;
  }

  #nav {
    background: rgba(255, 255, 255, 0.5);
    font-size: 1rem;
  }

  .guestbook-fields {
    grid-template-columns: 1fr;
  }

  .guestbook-actions {
    align-items: stretch;
    flex-direction: column;
  }

  .guestbook-actions button {
    width: 100%;
  }

  #rain-control {
    bottom: 0.85rem;
    left: 0.85rem;
  }

  .rain-control-panel {
    width: min(12.5rem, calc(100vw - 5.2rem));
  }
}

@media (prefers-reduced-motion: reduce) {
  html {
    scroll-behavior: auto;
  }

  #recent-posts > .recent-post-item,
  #recent-posts > .recent-post-item .post_cover img.post_bg {
    transition: none;
  }
}

Page.raw:
@import url("https://cdn.jsdelivr.net/npm/lxgw-wenkai-screen-webfont@1.7.0/style.css");

:root {
  --hane-ink: #2f4358;
  --hane-muted: #708596;
  --hane-soft: #edf7f9;
  --hane-glass: rgba(255, 255, 255, 0.6);
  --hane-glass-strong: rgba(255, 255, 255, 0.76);
  --hane-glass-border: rgba(255, 255, 255, 0.5);
  --hane-water: #9fd8ee;
  --hane-blush: #f2c8d6;
  --hane-mint: #c9eadf;
  --hane-iris: #aeb8dd;
  --hane-shadow: 0 16px 48px rgba(80, 118, 145, 0.16);
  --hane-blur: blur(18px) saturate(150%);
}

[data-theme='dark'] {
  --hane-ink: #dceaf3;
  --hane-muted: #a9bdcb;
  --hane-soft: #1b2d3a;
  --hane-glass: rgba(20, 31, 42, 0.58);
  --hane-glass-strong: rgba(28, 41, 55, 0.74);
  --hane-glass-border: rgba(185, 221, 238, 0.18);
  --hane-water: #7fc4e6;
  --hane-blush: #c99bb5;
  --hane-mint: #94d4c6;
  --hane-shadow: 0 18px 55px rgba(0, 0, 0, 0.34);
}

html {
  scroll-behavior: smooth;
}

html,
body,
button,
input,
textarea,
select {
  font-family: "LXGW WenKai Screen", "Noto Serif SC", "Songti SC", "Microsoft YaHei", sans-serif;
}

body {
  color: var(--hane-ink);
  background:
    linear-gradient(110deg, rgba(255, 255, 255, 0.72) 0 1px, transparent 1px 18px),
    radial-gradient(circle at 18% 12%, rgba(255, 255, 255, 0.86), transparent 28rem),
    radial-gradient(circle at 82% 18%, rgba(200, 234, 241, 0.58), transparent 30rem),
    radial-gradient(circle at 28% 82%, rgba(243, 203, 218, 0.4), transparent 32rem),
    linear-gradient(135deg, #f8fcfd 0%, #edf8fb 46%, #fbf3f7 100%) !important;
  background-size: 180px 180px, auto, auto, auto, auto !important;
  background-attachment: fixed !important;
}

[data-theme='dark'] body {
  background:
    radial-gradient(circle at 16% 10%, rgba(91, 140, 166, 0.32), transparent 28rem),
    radial-gradient(circle at 86% 18%, rgba(115, 92, 134, 0.28), transparent 30rem),
    radial-gradient(circle at 50% 88%, rgba(65, 107, 103, 0.22), transparent 34rem),
    linear-gradient(135deg, #101923 0%, #162433 52%, #211b2a 100%) !important;
}

body::before,
body::after {
  position: fixed;
  inset: 0;
  z-index: -3;
  pointer-events: none;
  content: "";
}

body::before {
  background-image:
    linear-gradient(rgba(255, 255, 255, 0.18) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255, 255, 255, 0.14) 1px, transparent 1px);
  background-size: 84px 84px;
  mask-image: linear-gradient(to bottom, transparent, #000 16%, #000 72%, transparent);
}

body::after {
  background:
    linear-gradient(105deg, transparent 0 46%, rgba(255, 255, 255, 0.1) 46.2%, transparent 47% 100%),
    linear-gradient(105deg, transparent 0 62%, rgba(159, 216, 238, 0.08) 62.2%, transparent 63% 100%);
  background-size: 620px 620px, 920px 920px;
  opacity: 0.28;
}

#web_bg,
#web_bg::before,
#footer::before,
#page-header::before {
  background: transparent !important;
}

#rain-canvas {
  position: fixed;
  inset: 0;
  z-index: 3;
  width: 100%;
  height: 100%;
  pointer-events: none;
  mix-blend-mode: screen;
}

#body-wrap,
#page-header,
#content-inner,
#footer,
#nav {
  position: relative;
}

#body-wrap,
#page-header,
#content-inner,
#footer {
  z-index: 2;
}

#page-header {
  overflow: hidden;
}

#page-header::after {
  position: absolute;
  inset: 0;
  z-index: 0;
  pointer-events: none;
  content: "";
  background:
    linear-gradient(to bottom, rgba(27, 51, 72, 0.12), rgba(238, 248, 251, 0.12) 52%, rgba(248, 252, 253, 0.34)),
    linear-gradient(115deg, transparent 0 53%, rgba(255, 255, 255, 0.08) 53.18%, transparent 54% 100%);
  background-size: auto, 780px 780px;
}

#page-header > * {
  position: relative;
  z-index: 1;
}

#page-header.full_page {
  min-height: 78vh;
}

#page-header.not-home-page {
  height: 22rem;
}

#page-header #site-info {
  box-sizing: border-box;
  width: 100%;
  max-width: none;
  padding: 0 1.25rem;
  margin: 0 auto;
  text-align: center;
  text-shadow: 0 10px 30px rgba(38, 65, 90, 0.42);
}

#site-title {
  letter-spacing: 0;
  color: rgba(255, 255, 255, 0.96);
  font-size: 2.55rem;
  font-weight: 700;
  line-height: 1.18;
}

#site-subtitle {
  display: block;
  max-width: 46rem;
  margin: 0.55rem auto 0;
  color: rgba(255, 255, 255, 0.9);
  line-height: 1.65;
  text-shadow: 0 8px 24px rgba(38, 65, 90, 0.34);
}

#subtitle {
  white-space: normal;
  overflow-wrap: anywhere;
}

#nav {
  background: rgba(255, 255, 255, 0.24);
  border-bottom: 1px solid rgba(255, 255, 255, 0.28);
  box-shadow: none;
  font-size: 1.08rem;
  font-weight: 600;
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

#nav.show {
  background: rgba(255, 255, 255, 0.66);
  box-shadow: 0 12px 32px rgba(91, 121, 150, 0.12);
}

[data-theme='dark'] #nav,
[data-theme='dark'] #nav.show {
  background: rgba(18, 29, 40, 0.58);
  border-bottom-color: rgba(185, 221, 238, 0.14);
}

#nav a,
#nav #site-name,
#nav .menus_item_child li a {
  color: var(--hane-ink);
}

#nav .menus_items .menus_item > a {
  display: inline-flex;
  gap: 0.22rem;
  align-items: center;
  height: 2.25rem;
  padding: 0 0.45rem;
  border-radius: 8px;
  transition: background 0.22s ease, color 0.22s ease, transform 0.22s ease;
}

#nav .menus_items .menus_item > a:hover {
  color: #3e7fa3;
  background: rgba(255, 255, 255, 0.36);
  transform: translateY(-1px);
}

#nav .site-page i,
#nav #toggle-menu i {
  margin-right: 0;
  font-size: 1.12rem;
  color: #6a9fbb;
}

#nav .site-name {
  font-size: 1.18rem;
}

#nav .menus_item_child,
#nav .menus_items .menus_item .menus_item_child {
  background: var(--hane-glass-strong);
  border: 1px solid var(--hane-glass-border);
  box-shadow: var(--hane-shadow);
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

#recent-posts > .recent-post-item,
.layout > div:first-child:not(.recent-posts),
.layout > .aside-content .card-widget,
#archive,
#page,
#post,
#tag,
#category,
#category-bar,
#pagination .page-number,
#pagination .extend,
#pagination .space {
  background:
    linear-gradient(145deg, rgba(255, 255, 255, 0.32), rgba(255, 255, 255, 0.08)),
    var(--hane-glass);
  border: 1px solid var(--hane-glass-border);
  box-shadow: var(--hane-shadow);
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

#recent-posts > .recent-post-item,
.layout > div:first-child:not(.recent-posts),
.layout > .aside-content .card-widget,
#archive,
#page,
#post,
#tag,
#category {
  border-radius: 8px;
}

#recent-posts > .recent-post-item {
  position: relative;
  overflow: hidden;
  transition: transform 0.25s ease, box-shadow 0.25s ease, border-color 0.25s ease;
}

#recent-posts > .recent-post-item::before {
  position: absolute;
  inset: 0 auto 0 0;
  width: 3px;
  content: "";
  background: linear-gradient(to bottom, var(--hane-water), var(--hane-blush), var(--hane-mint));
  opacity: 0.65;
}

#recent-posts > .recent-post-item:hover {
  border-color: rgba(159, 216, 238, 0.7);
  box-shadow: 0 22px 70px rgba(83, 127, 158, 0.22);
  transform: translateY(-4px);
}

#recent-posts > .recent-post-item .post_cover img.post_bg {
  filter: saturate(108%) contrast(96%) brightness(1.04);
  transition: transform 0.5s ease, filter 0.5s ease;
}

#recent-posts > .recent-post-item:hover .post_cover img.post_bg {
  filter: saturate(116%) contrast(98%) brightness(1.08);
  transform: scale(1.04);
}

.post-meta,
.post-meta a,
.article-meta-wrap,
.article-meta-wrap a,
.card-info-data,
.card-info-data a,
.aside-list .content time,
.aside-list .content .name {
  color: var(--hane-muted) !important;
}

#post-info .post-title,
.recent-post-info .article-title,
.card-widget .item-headline,
#page h1,
#post h1,
#archive h1,
#tag h1,
#category h1 {
  color: var(--hane-ink);
}

.recent-post-info .article-title {
  line-height: 1.45;
}

.recent-post-info .content,
#article-container {
  color: #40576a;
  line-height: 1.95;
}

[data-theme='dark'] .recent-post-info .content,
[data-theme='dark'] #article-container {
  color: #c8d8e2;
}

#article-container h1,
#article-container h2,
#article-container h3,
#article-container h4 {
  letter-spacing: 0;
}

a {
  color: #4a92b8;
}

a:hover {
  color: #d57d9f;
}

#aside-content .card-info .author-info-name {
  color: var(--hane-ink);
  font-size: 1.18rem;
}

#aside-content .card-info .author-info-description,
#aside-content .card-announcement .announcement_content {
  color: var(--hane-muted);
}

#aside-content .card-info #card-info-btn,
.button--animated,
#pagination .page-number.current {
  background: linear-gradient(135deg, #8fcde8, #d9bfdc);
  border: 0;
  box-shadow: 0 10px 24px rgba(104, 162, 188, 0.22);
  color: #fff !important;
}

#aside-content .card-info #card-info-btn:hover,
.button--animated:hover {
  box-shadow: 0 14px 32px rgba(132, 144, 189, 0.28);
  filter: brightness(1.03);
}

blockquote,
.note {
  background: rgba(255, 255, 255, 0.42) !important;
  border-color: rgba(159, 216, 238, 0.72) !important;
  border-radius: 8px;
}

[data-theme='dark'] blockquote,
[data-theme='dark'] .note {
  background: rgba(25, 38, 51, 0.58) !important;
}

hr {
  border-color: rgba(159, 216, 238, 0.42);
}

#footer {
  background: transparent;
  color: var(--hane-muted);
}

#footer a {
  color: var(--hane-ink);
}

#rightside > div > button,
#rightside > div > a {
  background: var(--hane-glass-strong);
  border: 1px solid var(--hane-glass-border);
  box-shadow: 0 10px 28px rgba(79, 119, 148, 0.18);
  color: var(--hane-ink);
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

.guestbook-board {
  display: grid;
  gap: 1.2rem;
}

.guestbook-form {
  display: grid;
  gap: 0.85rem;
  padding: 1.1rem;
  background: rgba(255, 255, 255, 0.42);
  border: 1px solid var(--hane-glass-border);
  border-radius: 8px;
}

[data-theme='dark'] .guestbook-form {
  background: rgba(24, 38, 51, 0.46);
}

.guestbook-fields {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(13rem, 1fr));
  gap: 0.85rem;
}

.guestbook-form input,
.guestbook-form textarea {
  width: 100%;
  padding: 0.8rem 0.9rem;
  color: var(--hane-ink);
  background: rgba(255, 255, 255, 0.62);
  border: 1px solid rgba(159, 216, 238, 0.44);
  border-radius: 8px;
  outline: none;
  transition: border-color 0.2s ease, box-shadow 0.2s ease, background 0.2s ease;
}

[data-theme='dark'] .guestbook-form input,
[data-theme='dark'] .guestbook-form textarea {
  background: rgba(13, 24, 35, 0.5);
}

.guestbook-form textarea {
  min-height: 8.5rem;
  resize: vertical;
}

.guestbook-form input:focus,
.guestbook-form textarea:focus {
  background: rgba(255, 255, 255, 0.78);
  border-color: rgba(213, 125, 159, 0.7);
  box-shadow: 0 0 0 4px rgba(159, 216, 238, 0.18);
}

.guestbook-actions {
  display: flex;
  flex-wrap: wrap;
  gap: 0.75rem;
  align-items: center;
  justify-content: space-between;
}

.guestbook-actions button {
  display: inline-flex;
  gap: 0.4rem;
  align-items: center;
  justify-content: center;
  min-height: 2.6rem;
  padding: 0 1.1rem;
  color: #fff;
  cursor: pointer;
  background: linear-gradient(135deg, var(--hane-water), var(--hane-blush));
  border: 0;
  border-radius: 8px;
  box-shadow: 0 10px 24px rgba(104, 162, 188, 0.22);
}

.guestbook-actions button[type='button'] {
  color: var(--hane-ink);
  background: rgba(255, 255, 255, 0.56);
  border: 1px solid var(--hane-glass-border);
}

.guestbook-hint {
  color: var(--hane-muted);
  font-size: 0.92rem;
}

.guestbook-list {
  display: grid;
  gap: 0.9rem;
}

.guestbook-empty,
.guestbook-message {
  padding: 1rem 1.05rem;
  background: rgba(255, 255, 255, 0.42);
  border: 1px solid var(--hane-glass-border);
  border-radius: 8px;
}

[data-theme='dark'] .guestbook-empty,
[data-theme='dark'] .guestbook-message {
  background: rgba(24, 38, 51, 0.46);
}

.guestbook-message-head {
  display: flex;
  gap: 0.7rem;
  align-items: baseline;
  justify-content: space-between;
  margin-bottom: 0.55rem;
}

.guestbook-message-name {
  color: var(--hane-ink);
  font-weight: 700;
}

.guestbook-message-date {
  color: var(--hane-muted);
  font-size: 0.86rem;
  white-space: nowrap;
}

.guestbook-message-body {
  margin: 0;
  color: var(--hane-ink);
  line-height: 1.9;
  white-space: pre-wrap;
}

.music-player-panel {
  display: grid;
  gap: 1rem;
}

.music-player-copy {
  padding: 1.1rem;
  background: rgba(255, 255, 255, 0.42);
  border: 1px solid var(--hane-glass-border);
  border-radius: 8px;
}

[data-theme='dark'] .music-player-copy {
  background: rgba(24, 38, 51, 0.46);
}

.music-player-copy h2 {
  margin: 0 0 0.35rem;
  color: var(--hane-ink);
}

.music-player-copy p {
  margin: 0;
  color: var(--hane-muted);
}

.music-page-aplayer.aplayer {
  margin: 0;
  overflow: hidden;
  color: var(--hane-ink);
  background: rgba(255, 255, 255, 0.54);
  border: 1px solid var(--hane-glass-border);
  border-radius: 8px;
  box-shadow: var(--hane-shadow);
}

[data-theme='dark'] .music-page-aplayer.aplayer {
  background: rgba(24, 38, 51, 0.6);
}

.music-page-aplayer.aplayer .aplayer-list,
.music-page-aplayer.aplayer .aplayer-info {
  border-color: rgba(159, 216, 238, 0.28);
}

.music-page-aplayer.aplayer .aplayer-list ol li {
  border-top-color: rgba(159, 216, 238, 0.2);
}

.music-page-aplayer.aplayer .aplayer-list ol li:hover,
.music-page-aplayer.aplayer .aplayer-list ol li.aplayer-list-light {
  background: rgba(159, 216, 238, 0.18);
}

#rain-control {
  position: fixed;
  bottom: 1.25rem;
  left: 1.25rem;
  z-index: 9;
  display: flex;
  gap: 0.65rem;
  align-items: end;
  pointer-events: none;
}

.rain-control-toggle,
.rain-control-panel {
  color: var(--hane-ink);
  pointer-events: auto;
  background:
    linear-gradient(145deg, rgba(255, 255, 255, 0.38), rgba(255, 255, 255, 0.12)),
    var(--hane-glass-strong);
  border: 1px solid var(--hane-glass-border);
  box-shadow: 0 14px 38px rgba(79, 119, 148, 0.18);
  backdrop-filter: var(--hane-blur);
  -webkit-backdrop-filter: var(--hane-blur);
}

.rain-control-toggle {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  width: 2.75rem;
  height: 2.75rem;
  color: #5c99b9;
  cursor: pointer;
  border-radius: 8px;
  transition: transform 0.22s ease, color 0.22s ease, box-shadow 0.22s ease;
}

.rain-control-toggle:hover,
#rain-control.is-open .rain-control-toggle {
  color: #d18ca8;
  box-shadow: 0 16px 42px rgba(105, 151, 178, 0.24);
  transform: translateY(-2px);
}

.rain-control-toggle i {
  font-size: 1.08rem;
}

.rain-control-panel {
  width: 12.5rem;
  padding: 0.8rem 0.9rem;
  border-radius: 8px;
  opacity: 0;
  transform: translateY(0.45rem) scale(0.98);
  transform-origin: bottom left;
  transition: opacity 0.22s ease, transform 0.22s ease, visibility 0.22s ease;
  visibility: hidden;
}

#rain-control.is-open .rain-control-panel {
  opacity: 1;
  transform: translateY(0) scale(1);
  visibility: visible;
}

.rain-control-head,
.rain-control-scale {
  display: flex;
  align-items: center;
  justify-content: space-between;
}

.rain-control-head {
  margin-bottom: 0.55rem;
  font-size: 0.95rem;
  font-weight: 700;
}

.rain-control-value {
  min-width: 1.65rem;
  padding: 0.08rem 0.45rem;
  color: #fff;
  text-align: center;
  background: linear-gradient(135deg, #8fcde8, #d9bfdc);
  border-radius: 8px;
}

.rain-control-range {
  width: 100%;
  height: 1.25rem;
  margin: 0;
  appearance: none;
  cursor: pointer;
  background: transparent;
}

.rain-control-range::-webkit-slider-runnable-track {
  height: 0.42rem;
  background:
    linear-gradient(90deg, rgba(111, 180, 211, 0.72), rgba(222, 176, 207, 0.82)) 0 / var(--rain-progress, 50%) 100% no-repeat,
    linear-gradient(90deg, rgba(159, 216, 238, 0.3), rgba(217, 191, 220, 0.36));
  border: 1px solid rgba(255, 255, 255, 0.52);
  border-radius: 8px;
}

.rain-control-range::-webkit-slider-thumb {
  width: 1rem;
  height: 1rem;
  margin-top: -0.34rem;
  appearance: none;
  background: #fff;
  border: 2px solid #7bb9d5;
  border-radius: 50%;
  box-shadow: 0 6px 16px rgba(93, 139, 164, 0.28);
}

.rain-control-range::-moz-range-track {
  height: 0.42rem;
  background:
    linear-gradient(90deg, rgba(111, 180, 211, 0.72), rgba(222, 176, 207, 0.82)) 0 / var(--rain-progress, 50%) 100% no-repeat,
    linear-gradient(90deg, rgba(159, 216, 238, 0.3), rgba(217, 191, 220, 0.36));
  border: 1px solid rgba(255, 255, 255, 0.52);
  border-radius: 8px;
}

.rain-control-range::-moz-range-thumb {
  width: 1rem;
  height: 1rem;
  background: #fff;
  border: 2px solid #7bb9d5;
  border-radius: 50%;
  box-shadow: 0 6px 16px rgba(93, 139, 164, 0.28);
}

.rain-control-scale {
  margin-top: 0.35rem;
  color: var(--hane-muted);
  font-size: 0.78rem;
}

::selection {
  background: rgba(159, 216, 238, 0.48);
  color: #23435b;
}

@media (max-width: 768px) {
  #page-header.full_page {
    min-height: 68vh;
  }

  #page-header.not-home-page {
    height: 17rem;
  }

  #site-title {
    font-size: 1.9rem;
  }

  #site-subtitle {
    max-width: 21rem;
    font-size: 0.96rem;
  }

  #recent-posts > .recent-post-item,
  .layout > div:first-child:not(.recent-posts),
  .layout > .aside-content .card-widget,
  #archive,
  #page,
  #post,
  #tag,
  #category {
    border-radius: 8px;
  }

  #nav {
    background: rgba(255, 255, 255, 0.5);
    font-size: 1rem;
  }

  .guestbook-fields {
    grid-template-columns: 1fr;
  }

  .guestbook-actions {
    align-items: stretch;
    flex-direction: column;
  }

  .guestbook-actions button {
    width: 100%;
  }

  #rain-control {
    bottom: 0.85rem;
    left: 0.85rem;
  }

  .rain-control-panel {
    width: min(12.5rem, calc(100vw - 5.2rem));
  }
}

@media (prefers-reduced-motion: reduce) {
  html {
    scroll-behavior: auto;
  }

  #recent-posts > .recent-post-item,
  #recent-posts > .recent-post-item .post_cover img.post_bg {
    transition: none;
  }
}

Page.content:
@import url("https://cdn.jsdelivr.net/npm/lxgw-wenkai-screen-webfont@1.7.0/style.css");

:root {
  --hane-ink: #2f4358;
  --hane-muted: #708596;
  --hane-soft: #edf7f9;
  --hane-glass: rgba(255, 255, 255, 0.6);
  --hane-glass-strong: rgba(255, 255, 255, 0.76);
  --hane-glass-border: rgba(255, 255, 255, 0.5);
  --hane-water: #9fd8ee;
  --hane-blush: #f2c8d6;
  --hane-mint: #c9eadf;
  --hane-iris: #aeb8dd;
  --hane-shadow: 0 16px 48px rgba(80, 118, 145, 0.16);
  --hane-blur: blur(18px) saturate(150%);
}

[data-theme='dark'] {
  --hane-ink: #dceaf3;
  --hane-muted: #a9bdcb;
  --hane-soft: #1b2d3a;
  --hane-glass: rgba(20, 31, 42, 0.58);
  --hane-glass-strong: rgba(28, 41, 55, 0.74);
  --hane-glass-border: rgba(185, 221, 238, 0.18);
  --hane-water: #7fc4e6;
  --hane-blush: #c99bb5;
  --hane-mint: #94d4c6;
  --hane-shadow: 0 18px 55px rgba(0, 0, 0, 0.34);
}

html {
  scroll-behavior: smooth;
}

html,
body,
button,
input,
textarea,
select {
  font-family: "LXGW WenKai Screen", "Noto Serif SC", "Songti SC", "Microsoft YaHei", sans-serif;
}

body {
  color: var(--hane-ink);
  background:
